import { Injectable } from "@angular/core";
import { CanActivate, CanActivateChild, Router } from "@angular/router";
import { NxService } from "../nx-library/nx.service";
import { ActiveUserModel } from "src/app/models/active-user.model";

@Injectable({
  providedIn: "root"
})
export class ActiveUserService {
  activeUserModel: ActiveUserModel;

  constructor(private router: Router, private nx: NxService) {
    this.activeUserModel = new ActiveUserModel();
    this.init();
  }

  init() {
    if (this.activeUserModel && !this.activeUserModel.isActive) {
      const user = localStorage.getItem("current-user");
      if (user) {
        this.activeUserModel = JSON.parse(user);
      }
    }
  }

  getUser() {
    return this.activeUserModel;
  }
  setUser(user: ActiveUserModel): void {
    this.activeUserModel = user;
    localStorage.setItem("current-user", JSON.stringify(user));
  }

  clearUser() {
    this.activeUserModel = new ActiveUserModel();
    localStorage.clear();
  }

  hasPermission(url: string) {
    const promise = new Promise((resolve, reject) => {
      let flag = false;
      setTimeout(() => {
        if (this.activeUserModel.isActive) {
          flag = true;
        } else {
          flag = false;
        }
        resolve(flag);
      }, 100);
    });
    return promise;
  }
}
