import { Injectable } from "@angular/core";

@Injectable({
  providedIn: "root"
})
export class NxDateService {
  constructor() {}

  getDateToString(date: Date) {
    const _date = new Date(date);
    const year = _date.getFullYear();
    let month = (1 + _date.getMonth()).toString();
    month = month.length > 1 ? month : "0" + month;
    let day = _date.getDate().toString();
    day = day.length > 1 ? day : "0" + day;
    return year + "-" + month + "-" + day;
  }

  getObjToDate(obj: any) {
    const date = new Date(obj.year, obj.month - 1, obj.day);
    return date;
  }
  getObjToDateString(obj: any) {
    const date = obj.year + "-" + obj.month + "-" + obj.day;
    return date;
  }

  getMinDateObj() {
    const currDate = new Date();
    const year = currDate.getFullYear();
    const month = currDate.getMonth() + 1;
    const day = currDate.getDate();
    return { year: year, month: month, day: day };
  }

  getMaxDateObj(year, month, day) {
    const currDate = new Date();
    let currYear = currDate.getFullYear() + year;
    let currMonth = currDate.getMonth() + 1;
    const currDay = currDate.getDate() + day;
    if (currMonth + month > 12) {
      currYear = currYear + 1;
      currMonth = currMonth + month - 12;
    }
    return { year: currYear, month: currMonth, day: currDay };
  }
}
