import { Component, OnInit, Input } from "@angular/core";
import {
  NgbModal,
  ModalDismissReasons,
  NgbActiveModal
} from "@ng-bootstrap/ng-bootstrap";
import { Router, ActivatedRoute } from "@angular/router";
import {
  FormBuilder,
  FormControl,
  FormGroup,
  Validators
} from "@angular/forms";
import { DataService } from "../../../../shared/services/data.service";
import { AppConfig } from "./../../../../app.config";
import { NxService } from "../../../../shared/nx-library/nx.service";

@Component({
  selector: "app-update-card",
  templateUrl: "./update-card.component.html",
  styleUrls: ["./update-card.component.css"]
})
export class UpdateCardComponent implements OnInit {
  cardForm: FormGroup;
  currentUser: any;
  @Input() cardData: any;
  isFrontSide: boolean;
  isEditMode: boolean;
  // vm = AppConfig.Message.Validation;
  constructor(
    private fb: FormBuilder,
    private ds: DataService,
    private router: Router,
    private nx: NxService,
    private activatedRoute: ActivatedRoute,
    public activeModal: NgbActiveModal
  ) {
    this.initializeForm();
  }

  ngOnInit() {
    this.isFrontSide = true;
    this.isEditMode = true;
    this.setFormData(this.cardData);
  }

  onRouteChange(path) {
    this.router.navigate([path]);
  }

  onSubmitForm() {
    // this._id.setValue(this.cardData._id);
    if (!this.cardForm.valid) {
      this.validateForm(this.cardForm);
    } else if (this.cardForm.valid) {
      const req = {
        url: AppConfig.Api.Card.Update,
        params: this.cardForm.value
      };
      this.ds.post(req).subscribe((res: any) => {
        if (res.status) {
          this.nx.message.success(res.message);
          this.activeModal.close(res);
        } else {
          this.nx.message.error(res.message);
        }
      });
    }
  }

  closeModal() {
    this.activeModal.close("Modal Closed");
  }

  get _id() {
    return this.cardForm.get("_id");
  }

  get cardFrontData() {
    return this.cardForm.get("cardFrontData");
  }
  get cardBackData() {
    return this.cardForm.get("cardBackData");
  }

  private initializeForm() {
    this.cardForm = this.fb.group({
      _id: ["", Validators.required],
      cardFrontData: "",
      cardBackData: ""
    });
  }

  private setFormData(model: any) {
    this.cardForm.patchValue({
      _id: model._id,
      cardFrontData: model.cardFrontData,
      cardBackData: model.cardBackData
    });
  }

  private validateForm(formGroup: FormGroup) {
    Object.keys(formGroup.controls).forEach(filed => {
      const control = formGroup.get(filed);
      if (control instanceof FormControl) {
        control.markAsTouched({ onlySelf: true });
      }
    });
  }
}
