import { Component, OnInit, Input, ViewChild } from '@angular/core';
import { NgbActiveModal } from "@ng-bootstrap/ng-bootstrap";

import {
  FormGroup,
  FormBuilder,
  Validators,
  FormControl,
  FormArray
} from "@angular/forms";

import { UploadService } from "./../../../shared/services/upload.service";
import { forkJoin } from "rxjs/observable/forkJoin";
import { NxService } from "../../../shared/nx-library/nx.service";

@Component({
  selector: "app-upload-dialog",
  templateUrl: "./upload-dialog.component.html",
  styleUrls: ["./upload-dialog.component.css"]
})
export class UploadDialogComponent implements OnInit {
  @Input() modelData: any;
  @ViewChild("file") file;
  public files: Set<File> = new Set();

  albumForm: FormGroup;
  imagesPath: any[] = [];
  displayImagesPath: any[] = [];
  imageItems: FormArray;

  progress;
  canBeClosed = true;
  primaryButtonText = "Upload";
  showCancelButton = true;
  uploading = false;
  uploadSuccessful = false;

  file_name: any;

  constructor(public activeModal: NgbActiveModal,
    public _uploadService: UploadService,
    public uploadService: UploadService,
    public nx: NxService) { }

  ngOnInit() {
  }

  onConfirmDelete() {
    this.activeModal.close(true);
  }

  closeModal() {
    this.activeModal.close(false);
  }

  addFiles() {
    this.file.nativeElement.click();
  }

  onFilesAdded() {
    const files: { [key: string]: File } = this.file.nativeElement.files;
    for (const key in files) {
      if (!isNaN(+key)) {
        const file_name = this.nx.utils.getUniqueFileName(1000000000, 9999999999) + '.' + files[key]['name'].split('.').pop();
        const blob = files[key].slice(0, files[key].size);
        const newFile = new File([blob], file_name);
        this.files.add(newFile);
        this.imagesPath.push(file_name);
        console.log(file_name);
        console.log(newFile);
        // this.files.add(files[key]); 
        // this.imagesPath.push(files[key]['name']);
      }
    }
  }


  closeDialog() {
    // if everything was uploaded already, just close the dialog
    console.log("***************** 1");
    if (this.uploadSuccessful) {
      console.log("***************",this.imagesPath);
      const data = {
        imagesPath: this.imagesPath
      };
      return this.activeModal.close(data);
      
    }
    console.log("***************** 2");
    // set the component state to "uploading"
    this.uploading = true;
    // start the upload and save the progress map
    console.log("progress Start");
    this.progress = this.uploadService.upload(this.files);
    console.log(this.progress);
    console.log("progress End");

    // convert the progress map into an array
    const allProgressObservables = [];
    for (const key in this.progress) {
      if (this.progress.hasOwnProperty(key)) {
        allProgressObservables.push(this.progress[key].progress);
      }
    }

    console.log("allProgressObservables");
    console.log(allProgressObservables);
    // for (const key in this.progress) {
    //     allProgressObservables.push(this.progress[key].progress);
    // }

    // Adjust the state variables

    // The OK-button should have the text "Finish" now
    this.primaryButtonText = "Finish";

    // The dialog should not be closed while uploading
    this.canBeClosed = false;
    // this.dialogRef.disableClose = true;

    // Hide the cancel-button
    this.showCancelButton = false;
    // When all progress-observables are completed...
    forkJoin(allProgressObservables).subscribe(end => {
      console.log("forkJoin");
      // ... the dialog can be closed again...
      this.canBeClosed = true;
      // this.dialogRef.disableClose = false;

      // ... the upload was successful...
      this.uploadSuccessful = true;

      // ... and the component is no longer uploading
      this.uploading = false;
    });
  }
}
