import { Component, OnInit } from "@angular/core";

import { NgbModal, ModalDismissReasons } from "@ng-bootstrap/ng-bootstrap";
import { ActivatedRoute, Router } from "@angular/router";
import { DataService } from "../../../shared/services/data.service";
import { AppConfig } from "../../../app.config";
import { AddCardComponent } from "./add-card/add-card.component";
import { UpdateCardComponent } from "./update-card/update-card.component";

@Component({
  selector: "app-card",
  templateUrl: "./card.component.html",
  styleUrls: ["./card.component.css"]
})
export class CardComponent implements OnInit {
  cardsList: any[];
  folderId: any;
  userId: any;
  currentUser: any;
  constructor(
    private activatedRoute: ActivatedRoute,
    private modalService: NgbModal,
    private router: Router,
    private ds: DataService
  ) {}

  ngOnInit() {
    const currentUser = localStorage.getItem("current-user");
    this.currentUser = JSON.parse(currentUser);
    this.userId = this.currentUser._id;
    this.activatedRoute.params.subscribe(params => {
      this.folderId = params.id;
      this.getAllCards(params.id);
    });
  }

  onDeleteConfirm(item: any) {
    // const modalRef = this.modalService.open(DeleteConfirmComponent);

    // modalRef.result
    //   .then(result => {
    //     if (result) {
    //       this.onDeleteCard(item._id);
    //     }
    //   })
    //   .catch(error => {
    //     console.log(error);
    //   });
  }

  onEditCard(item: any) {
    const modalRef = this.modalService.open(UpdateCardComponent, { size: 'lg' });
    modalRef.componentInstance.cardData = item;
    modalRef.result
      .then(result => {
        if (result) {
          // this.onDeleteCard(item._id);
          this.getAllCards(this.folderId);
        }
      })
      .catch(error => {
        console.log(error);
      });
  }

  onCreateCard() {
    const req = {
      url: AppConfig.Api.Card.Add,
      params: {
        userId: this.userId,
        folderId: this.folderId
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.cardsList.push(res.data);
        // this.nx.message.success(res.message);
      } else {
        // this.nx.message.error(res.message);
      }
    });
  }

  onDeleteCard(cardId: any) {
    const req = {
      url: AppConfig.Api.Card.Delete,
      params: {
        id: cardId
      }
    };
    this.ds.post(req).subscribe((res: any) => {
      if (res.status) {
        this.getAllCards(this.folderId);
      } else {
      }
    });
  }

  // open() {
  //   const modalRef = this.modalService.open(AddCardComponent);
  //   modalRef.componentInstance.currFolderId = this.folderId;

  //   modalRef.result
  //     .then(result => {
  //       this.cardsList.push(result.data);
  //       console.log(result + "Vijay SOni");
  //     })
  //     .catch(error => {
  //       console.log(error);
  //     });
  // }

  onClickCard(item: any) {}

  getAllCards(id: any) {
    const req = {
      url: AppConfig.Api.Card.GetByFolderId,
      params: {
        id: id
      }
    };
    this.ds.getById(req).subscribe((res: any) => {
      if (res.status) {
        this.cardsList = res.data;
      } else {
      }
    });
  }
}
