import { Injectable } from '@angular/core';
import * as moment from 'moment';

@Injectable({
  providedIn: 'root'
})
export class NxUtilsService {

  constructor() { }

  getRandamValue(min, max) {
    min = Math.ceil(min);
    max = Math.floor(max);
    return Math.floor(Math.random() * (max - min + 1)) + min; 
  }

  getUniqueFileName(min, max){
    min = Math.ceil(min);
    max = Math.floor(max);
    const rndNumber = Math.floor(Math.random() * (max - min + 1)) + min;
    const dateString = moment(new Date(), 'x');
    return dateString + "_" + rndNumber;
  }

  getFinancialYear() {
    let fYear = 0;
    const today = new Date();
    if ((today.getMonth() + 1) <= 3) {
      fYear = today.getFullYear() - 1;
    } else {
      fYear = today.getFullYear();
    }
    return fYear.toString();
  }

  getLastFinancialYearsList(lastYears: number): any[]{
    const financialList = [];
    let currFinancialYear = 0;
    const today = new Date();
    if ((today.getMonth() + 1) <= 3) {
        currFinancialYear = today.getFullYear() - 1;
    } else {
        currFinancialYear = today.getFullYear();
    }
    for (let i = (currFinancialYear - 1); i >= (currFinancialYear - 1 ) - (lastYears - 1); i--) {
        financialList.push({id: i, value: (i + '-' + (i + 1)) });
    }
    return financialList;
  }

}
