import { Injectable } from "@angular/core";
import { HttpClient, HttpHeaders, HttpParams } from "@angular/common/http";
import { Observable, of, throwError } from "rxjs";
import { map, catchError } from "rxjs/operators";
import { environment } from "./../../../environments/environment";
import { NxService } from "../nx-library/nx.service";
import { Router } from "@angular/router";

const httpOptions = {
  headers: new HttpHeaders({
    "content-type": "application/json"
  })
};

@Injectable({
  providedIn: "root"
})
export class DataService {
  env = environment;
  constructor(private http: HttpClient, private router: Router) {}

  get(request: any) {
    const url = this.env.serverUrl + request.url;
    return this.http.get(url).pipe(
      map((response: any) => {
        return response;
      }),
      catchError(error => {
        if (error.status === 500 && error.error && error.error.auth === false) {
          this.onRouteChange("auth/login");
        }
        return throwError(error);
      })
    );
  }

  getById(request: any) {
    const params = new HttpParams().set("id", request.params.id);
    const url = this.env.serverUrl + request.url;
    let Params = new HttpParams();
    Params = request.params;
    return this.http.get(url, { params }).pipe(
      map((response: any) => {
        return response;
      }),
      catchError(error => {
        if (error.status === 500 && error.error && error.error.auth === false) {
          this.onRouteChange("auth/login");
        }
        return throwError(error);
      })
    );
  }

  post(request: any) {
    const url = this.env.serverUrl + request.url;
    return this.http.post(url, request.params, httpOptions).pipe(
      map((response: any) => {
        return response;
      }),
      catchError(error => {
        if (error.status === 500 && error.error && error.error.auth === false) {
          this.onRouteChange("auth/login");
        }
        return throwError(error);
      })
    );
  }

  put(request: any) {}
  delete(request: any) {}

  onRouteChange(path) {
    this.router.navigate([path]);
  }
}
